+
+      let totalBytes = 0;
+      page.on("response", (response) => {
+        const headers = response.headers();
+        const contentLength = headers["content-length"];
+        if (contentLength) {
+          totalBytes += parseInt(contentLength, 10);
+        }
+      });
+
+      await page.goto(route, { waitUntil: "networkidle" });
